/**
 * Adapter: drive the SDK's multi-item Room Decorator engine through the
 * viewer's `ArRuntime` interface.
 *
 * SINGLE SOURCE OF TRUTH — the real WebXR engine lives in
 * `@novagates/ar-studio-web` (the package brands actually embed). The demo
 * viewer used to ship its own single-item copy; it now drives the exact
 * same engine the SDK ships, so there is no drift between "what we demo"
 * and "what a brand gets".
 *
 * The engine renders its own pre-session 3D preview + "View in your room"
 * CTA into the container and owns the fullscreen WebXR dom-overlay; this
 * adapter only maps its callbacks onto the viewer's runtime event bus.
 */

import { RuntimeEventBus } from './event-bus';
import type { ArRuntime, RuntimeEventListener, RuntimePath } from './types';
import type { Item } from '@nova-ar/types';
import type { RoomEngineHandle } from '@novagates/ar-studio-web/engine';

export interface NovaRoomRuntimeOptions {
  /** Catalog shown in the in-AR product tray (place several items). */
  readonly catalog?: readonly Item[];
  /** Locale-aware price formatter for the shopping UI. */
  readonly formatPrice?: (item: Item) => string;
}

export function createNovaRoomRuntime(opts: NovaRoomRuntimeOptions = {}): ArRuntime {
  const bus = new RuntimeEventBus();
  let handle: RoomEngineHandle | null = null;

  return {
    runtimePath: 'webxr' as RuntimePath,

    async launch(item: Item, container: HTMLElement): Promise<void> {
      const { startRoomDecorator } = await import('@novagates/ar-studio-web/engine');
      handle = await startRoomDecorator({
        activeItem: item,
        container,
        catalog: opts.catalog,
        formatPrice: opts.formatPrice,
        callbacks: {
          onSessionStart: () => bus.emit({ kind: 'session.start', runtimePath: 'webxr' }),
          onSessionEnd: () => bus.emit({ kind: 'session.end' }),
          onPlaced: (p) =>
            bus.emit({
              kind: 'item.placed',
              placementId: p.placementId,
              itemId: p.itemId,
              placement: p.placement,
              pose: p.pose,
            }),
          onRemoved: (placementId) => bus.emit({ kind: 'item.removed', placementId }),
          onAddToCart: (it) => {
            if (typeof window !== 'undefined') {
              window.dispatchEvent(
                new CustomEvent('nova-ar-add-to-cart', {
                  detail: { itemId: it.id, sku: it.sku, price: it.price },
                }),
              );
            }
          },
          onError: (code, message) => bus.emit({ kind: 'error', code, message }),
        },
      });
    },

    on(listener: RuntimeEventListener): () => void {
      return bus.on(listener);
    },

    async end(): Promise<void> {
      if (handle) {
        await handle.end().catch(() => undefined);
        handle = null;
      } else {
        bus.emit({ kind: 'session.end' });
      }
      bus.clear();
    },
  };
}
